		}

	}

    scwin.grdGubun = gubun;
    udc_comCodeGrid.setSelectId(pSelectID);
	rtnList = udc_comCodeGrid.cfCommonPopUp(scwin.udc_comCodeGridCallback,						//pSelectID   
							pCode,							//pCode
							pName,							//pName
							pWinCloseTF,					//pWinCloseTF
							pDispCnt,						//pDispCnt
							null,							//pTitle
							null,							//pWidth
							pHidden,						//pHidden
							pWhere,							//pWhere
							null,							//pW
							null,							//pH
							null,							//pTop
							null,							//pLeft
							null,							//pExistTF - 중복체크여부	("F")
							"F",							//pAllSearchTF - 전체검색허용여부	("F")
							pWtitleSearch);					//pWtitleSearch - POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")

/*
