scwin.gr_selldecunsetdetail_oneditkeyup = function (info) {
    const inputEl = event.target;

    switch (info.colID) {
        case "bilgLodeptCd" : 
            inputEl.value = info.newValue.toUpperCase();
            break;
        case "vsslCd" : 
            inputEl.value = info.newValue.toUpperCase();
            break;
        case "tsVsslCd" : 
            inputEl.value = info.newValue.toUpperCase();
            break;
        default :
            break;
    }
};

